PLACEHOLDER_NAMES = {"alice", "bob", "eve", "jane doe", "john doe", "user", "example"}
PRODUCT_KEYWORDS = {"sdk", "api", "model", "framework", "library", "package", "module"}

def context_validate(text: str, findings: list[Finding]) -> list[Finding]:
    """
    Filter out findings that are likely false positives based on context.
    """
    validated = []
    words_lower = set(text.lower().split())

    for f in findings:
        if f.entity_type == "PERSON_NAME":
            if f.value.lower() in PLACEHOLDER_NAMES:
                continue
            # Drop person names surrounded by product keywords
            context_window = text[max(0, f.start - 50): f.end + 50].lower()
            if any(kw in context_window for kw in PRODUCT_KEYWORDS):
                continue
        validated.append(f)
    return validated

from dataclasses import dataclass
from typing import Callable

@dataclass
class ScanResult:
    findings: list[Finding]
    risk_level: str        # "clean" | "medium" | "high" | "critical"
    blocked: bool

CRITICAL_TYPES = {"SSN", "CREDIT_CARD", "API_KEY", "PERSON_NAME", "HEALTH_DATA"}
HIGH_TYPES     = {"EMAIL", "PHONE_US", "PASSPORT", "FINANCIAL"}

def scan_text(text: str, block_on_critical: bool = True) -> ScanResult:
    """Run full PII detection pipeline and return a ScanResult."""
    regex_findings = regex_scan(text)
    ner_findings   = ner_scan(text)
    all_findings   = context_validate(text, regex_findings + ner_findings)

    types_found = {f.entity_type for f in all_findings}

    if types_found & CRITICAL_TYPES:
        risk = "critical"
        blocked = block_on_critical
    elif types_found & HIGH_TYPES:
        risk = "high"
        blocked = False
    elif all_findings:
        risk = "medium"
        blocked = False
    else:
        risk = "clean"
        blocked = False

    return ScanResult(findings=all_findings, risk_level=risk, blocked=blocked)


# Integration point — call before chunking or embedding
def pii_gate(text: str, document_id: str, policy: str = "strict") -> tuple[str, ScanResult]:
    """
    Gate document text through PII detection.
    Returns (cleared_text, scan_result).
    Raises ValueError if blocked.
    """
    result = scan_text(text, block_on_critical=(policy == "strict"))
    if result.blocked:
        raise ValueError(
            f"Document {document_id} blocked: {result.risk_level} PII detected "
            f"({[f.entity_type for f in result.findings]})"
        )
    return text, result

from dataclasses import dataclass

@dataclass
class CalibrationResult:
    entity_type: str
    true_positives: int
    false_positives: int
    false_negatives: int

    @property
    def precision(self) -> float:
        tp, fp = self.true_positives, self.false_positives
        return tp / (tp + fp) if (tp + fp) > 0 else 0.0

    @property
    def recall(self) -> float:
        tp, fn = self.true_positives, self.false_negatives
        return tp / (tp + fn) if (tp + fn) > 0 else 0.0

    @property
    def f1(self) -> float:
        p, r = self.precision, self.recall
        return 2 * p * r / (p + r) if (p + r) > 0 else 0.0


def calibrate(labeled_docs: list[dict]) -> list[CalibrationResult]:
    """
    labeled_docs: list of {"text": str, "spans": [{"type": str, "start": int, "end": int}]}
    Returns calibration metrics per entity type.
    """
    from collections import defaultdict
    stats = defaultdict(lambda: {"tp": 0, "fp": 0, "fn": 0})

    for doc in labeled_docs:
        text = doc["text"]
        truth = {(s["type"], s["start"], s["end"]) for s in doc["spans"]}
        result = scan_text(text, block_on_critical=False)
        predicted = {(f.entity_type, f.start, f.end) for f in result.findings}

        for span in predicted:
            if span in truth:
                stats[span[0]]["tp"] += 1
            else:
                stats[span[0]]["fp"] += 1
        for span in truth:
            if span not in predicted:
                stats[span[0]]["fn"] += 1

    return [
        CalibrationResult(et, s["tp"], s["fp"], s["fn"])
        for et, s in stats.items()
    ]
